dark.customCSS:
/* --- SOVEREIGN: ARCHITECTURAL MATERIAL UI --- */

/* High-End Glassmorphism */
#sidebar {
	background: rgba(12, 17, 29, 0.7) !important;
	backdrop-filter: blur(24px) !important;
	-webkit-backdrop-filter: blur(24px) !important;
	border-right: 1px solid rgba(255, 255, 255, 0.04) !important;
}

/* The Sovereign Floating Panel */
.markdown-prose, .bg-gray-850, input, textarea, #chat-input-container {
	background: rgba(17, 24, 39, 0.5) !important;
	border: 1px solid rgba(255, 255, 255, 0.08) !important;
	border-radius: 16px !important;
	box-shadow: 0 10px 30px -10px rgba(0, 0, 0, 0.5) !important;
	transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

/* Interactive Depth */
input:focus, textarea:focus, #chat-input-container:focus-within {
	border-color: rgba(255, 255, 255, 0.2) !important;
	box-shadow: 0 15px 40px -10px rgba(0, 0, 0, 0.7) !important;
	transform: translateY(-1px);
}

/* Elegant Typography */
.markdown-prose h1, .markdown-prose h2, .markdown-prose h3 {
	font-family: 'Inter', system-ui, sans-serif !important;
	font-weight: 300 !important;
	letter-spacing: -0.02em;
	color: #fff !important;
	opacity: 0.9;
}

/* Backlit 'Moonstone' Buttons */
button.bg-blue-500, button.bg-blue-600, .bg-black {
	background: #fff !important;
	color: #000 !important;
	border-radius: 12px !important;
	font-weight: 700 !important;
	text-transform: uppercase;
	letter-spacing: 0.1em;
	font-size: 0.7rem !important;
	border: none !important;
	box-shadow: 0 0 20px rgba(255, 255, 255, 0.1);
	transition: all 0.3s ease;
}

button.bg-blue-500:hover {
	box-shadow: 0 0 30px rgba(255, 255, 255, 0.3) !important;
	transform: translateY(-2px);
	background: #eef1f8 !important;
}

/* Minimalist Scrollbar */
::-webkit-scrollbar {
	width: 6px;
}
::-webkit-scrollbar-thumb {
	background: rgba(255, 255, 255, 0.1) !important;
	border-radius: 10px;
}
::-webkit-scrollbar-track {
	background: transparent !important;
}

dark.canvasScript:
/**
 * Title: Prismatic Caustics
 * Description: Shifting light patterns simulating refraction through glass.
 */

const CONFIG = {
    blobCount: 4,
    speed: 0.005,
    colors: [
        'rgba(100, 150, 255, 0.08)', 
        'rgba(200, 100, 255, 0.05)', 
        'rgba(255, 255, 255, 0.03)',
        'rgba(50, 200, 255, 0.06)'
    ]
};

let canvas, ctx, w, h;
let blobs = [];

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    blobs = [];
    for (let i = 0; i < CONFIG.blobCount; i++) {
        blobs.push({
            x: Math.random() * w, y: Math.random() * h,
            r: Math.random() * 500 + 400,
            vx: (Math.random() - 0.5) * 2,
            vy: (Math.random() - 0.5) * 2,
            color: CONFIG.colors[i % CONFIG.colors.length]
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);

    // Use screen blending to create soft prismatic overlays
    ctx.globalCompositeOperation = 'screen';

    for (let b of blobs) {
        b.x += b.vx; b.y += b.vy;
        if (b.x < -b.r) b.x = w + b.r; if (b.x > w + b.r) b.x = -b.r;
        if (b.y < -b.r) b.y = h + b.r; if (b.y > h + b.r) b.y = -b.r;

        let grad = ctx.createRadialGradient(b.x, b.y, 0, b.x, b.y, b.r);
        grad.addColorStop(0, b.color);
        grad.addColorStop(1, 'rgba(0,0,0,0)');

        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
        ctx.fill();
    }

    requestAnimationFrame(render);
}

